  ('social-worker-moex-06400', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於憂鬱症，下列敘述何者正確？ 憂鬱症在青少年時期的盛行率（prevalence）最高 憂鬱症的患者女性多於男性 大部分的自殺者並沒有憂鬱的現象 憂鬱症的治療效果不佳', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06401', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於愛滋病的資訊，下列敘述何者正確？ 症狀會依患者的免疫力、感染細菌的種類及感染的部位而不同 潛伏期從3個月到1年，慢者7到10年，或者更久 愛滋病是第二類法定傳染病 感染者遭受不平等待遇時，可自事發日起6個月內依法提出申訴', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06402', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於我國的兒童虐待的現象，下列敘述何者錯誤？ 兒童虐待通報和確認的人數有逐年上升的趨勢 最近三年，責任通報來源最多的是社會工作人員 一般而言，遭受身體虐待的男性多於女性 我國0-3歲嬰幼兒受虐的比率比美國低', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06403', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述何者不是艾瑞克森（E. Erikson）之心理社會發展理論的主張？ 心理社會發展分為八個階段 每個發展階段都有個體必須處理的生理、情緒和認知任務 個體若能圓滿解決每個發展階段的危機/衝突，自我效能必將提升 個體完成某個階段性的任務後，再也不必面對同樣的困擾', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06404', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '學者費雪（Fischer）提到，對老年人而言何者為靈性的意涵？ 靈性就是宗教  享受孤獨的晚年生活  尋求和解與寬恕  為死亡做準備', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06405', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於Achenbach的兒童行為檢核表（Child Behavior Checklist），下列敘述何者正確？ 可以用來篩檢自閉症 量表內容包括退縮、強迫性想法、社交問題、衝動行為與偏差行為等 施測時是由父母、老師及兒童填寫 目前並無中文版', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06406', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於兒童期的發展，下列兒童自閉症的敘述何者錯誤？ 3歲以下的兒童，不易做出注意力不足過動症的診斷 診斷注意力不足過動症，必須確定兒童的注意力不足或過動衝動症狀至少持續12個月 思覺失調症（原稱精神分裂症）或自閉症都有嚴重的情緒失調症狀 自閉症與亞斯柏格症（Asperger''s disorder）有許多相似的症狀，差別在後者沒有語言遲緩的問題', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06407', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據佛洛依德的心理分析論，下列何者是固著於肛門期發展階段的特徵？ 強迫行為  同性戀  變性症  自戀', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06408', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在產檢的項目中，關於羊膜穿刺術，下列敘述何者正確？ 每次懷孕都要執行    懷孕的第24週以後執行 可以檢查出唐氏症等染色體異常  百分之百安全，沒有併發症', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06409', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在與團體工作的過程中，下列何種角色不以任務為取向？ 評論者  導引者  推敲者  觀察員', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
